import { Language } from '@govflanders/vl-widget-shared';
/**
 * Callback function that is executed when a language is selected in the language switcher.
 * @param language - The language code that was selected (e.g., 'nl', 'en', 'fr', 'de')
 */
export type LanguageSwitcherCallback = (language: Language) => void;
/**
 * Configuration object for language navigation links.
 * Used when you want the language switcher to navigate to a specific URL instead of calling a callback.
 */
export interface LanguageLink {
    /** The URL to navigate to when this language is selected */
    href: string;
}
/**
 * Configuration object for the language switcher component.
 * Maps language codes to either callback functions or navigation links.
 *
 * @example
 * // Using callbacks for custom language change handling
 * const config: LanguageSwitcherConfig = {
 *   nl: (language) => i18n.setLocale('nl'),
 *   en: (language) => i18n.setLocale('en')
 * };
 *
 * // Using navigation links for URL-based language switching
 * const config: LanguageSwitcherConfig = {
 *   nl: { href: '/nl/current-page' },
 *   en: { href: '/en/current-page' }
 * };
 *
 * // Mixed approach - some languages use callbacks, others use links
 * const config: LanguageSwitcherConfig = {
 *   nl: (language) => i18n.setLocale('nl'),
 *   en: { href: '/en' }
 * };
 */
export type LanguageSwitcherConfig = Partial<Record<Language, LanguageLink | LanguageSwitcherCallback>>;
export interface LanguageSwitcherMethods {
    /**
     * Configure language change behavior for each supported language.
     * @param config - A partial record mapping language codes to either a callback function (called when language changes) or a URL string (for navigation).
     * @returns A promise that resolves to a boolean, confirming if the configuration was successfully applied.
     * @example
     * // Using callbacks
     * const success = await globalHeaderClient.languageSwitcher.configure({
     *   nl: (language) => console.log('Changed to Dutch'),
     *   en: (language) => console.log('Changed to English')
     * });
     *
     * // Using Link objects for navigation
     * const success = await globalHeaderClient.languageSwitcher.configure({
     *   nl: { href: '/nl' },
     *   en: { href: '/en' }
     * });
     */
    configure: (config: LanguageSwitcherConfig) => Promise<boolean>;
}
